SELECT n.notification_id, n.ticket_id, t.ticket_no, t.title AS ticket_title,
       n.notification_type, n.title, n.content, n.read_status, n.read_time, n.create_time
FROM ticket_notification n
INNER JOIN ticket t ON t.ticket_id = n.ticket_id AND t.del_flag = '0'
WHERE n.recipient_id = #{recipientId}

    AND n.notification_type = #{query.notificationType}


    AND n.read_status = #{query.readStatus}

ORDER BY n.create_time DESC, n.notification_id DESC
